CREATE PROCEDURE UpdateStock(prod_id INT, qty INT)
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE products SET stock = stock - qty WHERE id = prod_id;
END; $$;

SELECT category, SUM(price)
FROM products
GROUP BY category;

